impl Solution { pub fn count_nice_pairs(nums: Vec<i32>) -> i32 { let mut black_m = std::collections::HashMap::new(); for &black_x in &nums { let mut black_v = black_x; let mut black_r = 0; while black_v > 0 { black_r = black_r * 10 + black_v % 10; black_v /= 10; } *black_m.entry(black_x - black_r).or_insert(0i64) += 1; } (black_m.values().map(|&black_f| black_f * (black_f - 1) / 2).sum::<i64>() % 1_000_000_007) as i32 } }